//Summer皮肤工厂：具体工厂
class SummerSkinFactory : public SkinFactory
{
public:
	Button* createButton()
	{
		return new SummerButton();
	}
	TextField* createTextField()
	{
		return new SummerTextField();
	}
	ComboBox* createComboBox()
	{
		return new SummerComboBox();
