#### 任务处理完毕，回收多余线程

超过initThreadSize\_数量的线程要进行回收。

当前时间比上一次线程执行完毕的时间大于60s后回收。

> C11中提供了高精度时间API - high\_resolution\_clock().now();

```cpp
const int THREAD_IDLE_TIME = 60;	//单位s
void ThreadPool::threadFunc()
{
    /* 上一次线程执行完任务的时间 */
    auto lastTime = std::chrono::high_resolution_clock().now();
    for(;;)
    {
    	std::unique_ptr<Task> task;
        {
            std::unique_lock<std::mutex> lock(taskQueMtx_);
			/* 尝试获取任务 */
            if(poolMode_ == PoolMode::MODE_CACHED)
            {
                /* 每一秒钟返回一次 */
                while(taskQue_.size() == 0)
                {
                    /* 超时返回 */
                    if(std::cv_status::timeout ==
                       notEmpty_.wait_for(lock, std::chrono::seconds(1)))
                    {
                        auto now = std::chrono::high_resolution_clock().now();//返回的是time_point类型
                        auto dur = std::chrono::duration_cast<std::chrono::seconds>(now - lastTime);
                    	if(dur.count() >= THREAD_MAX_IDLE_TIME
                          && curThreadSize_ > initThreadSize_)
                        {
                            /* 开始回收当前线程 */
                            /* 修改记录线程数量的相关变量 */
                            /* 把线程从线程列表容器中删除 */
                            /* 问题：怎么知道线程函数对应的是线程列表容器中的哪一个线程对象 */
                            /* 我们需要有一个映射关系来记录：threadid => thread对象 => 删除 */
                        }
                    }
                }
            }
            else
            {
                notEmpty_.wait(lock, [&]()->bool{return taskQue_.size() > 0;});
            }
            --idleThreadSize_;
        }
    /*			...			*/

    }
    if(task!=nullptr)task->exec();
    ++idleThreadSize_;

    /* 线程执行完任务后更新lastTime */
    lastTime = std::chrono::high_resolution_clock().now();
}
```

