加锁

```cpp
#include<iostream>
std::mutex g_mtx;
std::condition_variable cv;
int number = 0;
void fun0()
{
    unique_lock<std::mutex> locker(g_mtx);
    while(number <= 100)
    {
        while(number%3==0 && number <= 100)
