# 二叉搜索树--类C结构体

## 节点结构

* 节点结构

```c++
typedef int KeyType;
typedef struct BstNode
{
	KeyType key;
	BstNode* leftchild;
	BstNode* parent;
	BstNode* rightchild;
}BstNode,*BSTree;
```

* Buynode

```c++
BstNode* Buynode()
{
	BstNode* s = (BstNode*)malloc(sizeof(BstNode));
	if (NULL == s)exit(1);
	memset(s, 0, sizeof(BstNode));
	return s;
}
```

## Insert

```c++
BstNode* MakeRoot(KeyType kx)
{
	BstNode* pnode = Buynode();
	pnode->key = kx;
	return pnode;
}
bool Insert(BstNode*& ptr, KeyType kx)
{
	if (ptr == NULL)
	{
		ptr = MakeRoot(kx);
		return true;
	}
	BstNode* p = ptr;	//遍历Node的指针
	BstNode* pa = NULL;	//实时追踪p的parent
	while (p != NULL && p->key != kx)
	{
		pa = p;
		p = kx < p->key ? p->leftchild : p->rightchild;
	}
	/* 实际上不用再判断p->key == kx, 只要p != NULL就说明找到了相等的节点，
	   如果此时p!=NULL的话，上面的while循环的退出就是因为p->key==kx而退出的
	*/
	if (p != NULL /* && p->key == kx */)return false;

	// 此时已经找到要插入的位置
	p = Buynode();
	p->key = kx;
	p->parent = pa;
	// 更新pa的左或右孩子
	if (p->key < pa->key) pa->leftchild = p;
	else pa->rightchild = p;
	return true;
}
```

代码结构优化--Insert中包含了建根的情况

```c++
bool Insert(BstNode*& ptr, KeyType kx)
{
	BstNode* p = ptr;	//遍历Node的指针
	BstNode* pa = NULL;	//实时追踪p的parent
	while (p != NULL && p->key != kx)
	{
		pa = p;
		p = kx < p->key ? p->leftchild : p->rightchild;
	}
	if (p != NULL)return false;

	// 此时已经找到要插入的位置			//其中，包括根为空的情况
	p = Buynode();
	p->key = kx;
	p->parent = pa;
    if(pa == NULL)	//建根的情况
    {
        ptr = p;
    }
    else // 更新pa的左或右孩子
    {
        if(p->key < pa->key)
            pa->leftchild = p;
        else 
            pa->rightchild = p;
    }
    return true;
}
```

