//cpp生成的符号的方式是取决于函数名和参数列表。
//而c生成的符号只是函数名
//所以导致符号找不到。
int main()
{
    fun_C();
    return 0;
}
//如何解决——使用C语言的方式编译和生成符号。
extern "C"
{
    void fun_C();//声明
}
```

