{
	if (m == 0 || n == 0)return 0;
	else
	{
		if (X[m] == Y[n])return LCSLength(X, m - 1, Y, n - 1) + 1;
		else
		{
			int max1 = LCSLength(X, m - 1, Y, n);
			int max2 = LCSLength(X, m, Y, n - 1);
