void Partition(int* ar, int left, int right)
{
    int tmp = ar[left];
    while(left < right)
    {
        while(left<right && br[right]>tmp)--right;
        if(left < right) br[left] = br[right];
        while(left<right) && br[left]<=tmp)++left;
        if(left < right) br[right] = br[left];
