void QuickSort(int* ar, int n)
{
    if(ar==NULL || n<=1)return;
    queue<int> qu;
    qu.push(0);
    qu.push(n-1);
    while(!qu.empty())
    {
        int left = qu.front(); qu.pop();
        int right = qu.front();qu.pop();
        int pos = Partition(ar, left, right);
        if(left < pos-1)
        {
            qu.push(left);
            qu.push(pos-1);
        }
        if(pos+1 < right)
        {
            qu.push(pos+1);
            qu.push(right);
        }
    }
}
