# mstring.cpp

```cpp
#include"mstring.h"

mutex* Mstring::_lock = new mutex();

Mstring::Mstring(const char* str)
{
	if (NULL == str)
	{
		_len = DEFEALT_LEN;
		_val_len = 0;
		_str = new char[_len];
		memset(_str, 0, _len);
		init_num();
		return;
	}

	_val_len = strlen(str);

	//加上引用计数占的空间
	_len = _val_len + 1 + MSTRING_MORE_SIZE;
	_str = new char[_len];
	memset(_str, 0, _len);

	for (int i = 0; i < _val_len; i++)
	{
		get_str_begin()[i] = str[i];
	}
	init_num();
}

Mstring::Mstring(const Mstring& src)
{
	_val_len = src._val_len;
	_len = src._len;
	_str = src._str;
	//让引用计数+1
	up_num();
}

Mstring& Mstring::operator=(const Mstring& src)
{
	if (&src == this)
	{
		return *this;
	}
	_val_len = src._val_len;
	_len = src._len;
	_str = src._str;
	up_num();

	return *this;
}

Mstring::~Mstring()
{
	//将引用计数-1
	down_num();

	//查看当前是否还有人引用
	if (0 == get_num())
	{
		delete[]_str;
	}
}

void Mstring::push_back(char c)
{
	//判断是否一个人独有
	if (get_num() > 1)
	{
		//写时拷贝，给分配独有的空间
		write_copy();
	}

	if (full())
	{
		expand();
	}

	get_str_begin()[_val_len] = c;
	_val_len++;
}

void Mstring::pop_back()
{
	if (get_num() > 1)
	{
		write_copy();
	}

	if (empty())
	{
		return;
	}

	_val_len--;
}

char Mstring::back()const
{
	if (empty())
	{
		return 0;
	}

	return get_str_begin()[_val_len - 1];
}

char Mstring::front()const
{
	if (empty())
	{
		return 0;
	}

	return get_str_begin()[0];
}

bool Mstring::empty()const
{
	return _val_len == 0;
}

Mstring Mstring::operator+(const Mstring& str)const
{
	char* p;
	int len = _val_len + str._val_len + 1;
	p = new char[len];
	memset(p, 0, len);

	//进行数据拷贝-----将两个字符串的数据拼接起来
	int i = 0;
	for (; i < _val_len; i++)
	{
		p[i] = get_str_begin()[i];
	}

	for (int j = 0; j < str._val_len; j++, i++)
	{
		p[i] = str.get_str_begin()[j];
	}

	return p;
}

char& Mstring::operator[](int pos)
{
	if (get_num() > 1)
	{
		write_copy();
	}
	return  get_str_begin()[pos];
}

char Mstring::operator[](int pos)const
{
	return  get_str_begin()[pos];
}

bool Mstring::full()const
{
	return _val_len == _len - 1 - MSTRING_MORE_SIZE;
}

void Mstring::expand()
{
	if (get_num() > 1)
	{
		write_copy();
	}

	_len = _len << 1;

	char* p = new char[_len];
	memset(p, 0, _len);

	for(int i = 0;i<_val_len+MSTRING_MORE_SIZE;i++)
	{
		p[i] = _str[i];
	}

	if (down_num() == 0)
	{
		delete[]_str;
	}

	_str = p;
}

int Mstring::size()const
{
	return _val_len;
}

//初始化引用计数
void Mstring::init_num()
{
	get_num() = 1;
}

//获取引用计数
int& Mstring::get_num()
{
	return *((int*)_str);
}

//引用计数-1
int Mstring::down_num()
{
	_lock->lock();
	int num = --get_num();
	_lock->unlock();
	return num;
}

//引用计数+1
int Mstring::up_num()
{
	//get_lock()->lock();
	_lock->lock();
	/*
	while(1)
	{
		if(_lock->a == 0)
		{
			_lock->a = 1;
			break;
		}
		sleep(10);
	}

	*/
	int num = ++get_num();
	_lock->unlock();
	/*
	_lock->a = 0;
	*/

	return num;
}


//获取引用计数
int Mstring::get_num()const
{
	return *((int*)_str);
}

//获取字符串的开头指针
char* Mstring::get_str_begin()
{
	return _str + MSTRING_MORE_SIZE;
}

//获取字符串的开头指针
const char* Mstring::get_str_begin()const
{
	return _str + MSTRING_MORE_SIZE;
}

//写时拷贝
void Mstring::write_copy()
{
	char* p = new char[_len];

	//将所有的数据全部拷贝过来
	for (int i = 0; i < _len; i++)
	{
		p[i] = _str[i];
	}

	//改变原来指向的内存的引用计数
	if (0 == down_num())
	{
		delete[]_str;
	}

	//将当前引用计数改为1
	_str = p;
	init_num();
}

ostream& operator<<(ostream& out, const Mstring& src)
{
	for (int i = 0; i < src.size(); i++)
	{
		out << src.get_str_begin()[i];
	}
	out << "     :::::num:::" << src.get_num();
	out << endl;
	return out;
}

istream& operator>>(istream& in, Mstring& src)
{
	if (src.get_num() > 1)
	{
		src.write_copy();
	}

	char tmp[1024];
	in >> tmp;

	src = tmp;
	return in;
}

////////////////////////////////迭代器

iterator Mstring::begin()
{
    return iterator(*this, 0);
}

iterator Mstring::end()
{
    return iterator(*this, _val_len);
}
iterator Mstring::insert(iterator it, char val) 
{
    //判断是否独有
    if (get_num() > 1)
    {
        write_copy();
    }

    //扩容
    if (full())
    {
        expand();
    }

    iterator it1 = end();
    iterator it2 = it1 - 1;

    for (; it1 != it; it1--, it2--)
    {
        *it1 = *it2;
    }
    *it = val;
    _val_len++;

    return it;
}
iterator Mstring::erase(iterator it)
{
    //判断是否独有
    if (get_num() > 1)
    {
        write_copy();
    }

    //判空
    if (empty())
    {
        return it;
    }

    iterator it1 = it;
    iterator it2 = it + 1;
    for (; it2 != end(); it1++, it2++)
    {
        *it1 = *it2;
    }

    _val_len--;
    return it;
}


char& Mstring_iterator::operator*()
{
	return _mstr[_pos];
}
