## list.cpp

```cpp
#include"list.h"
#include<stdio.h>
/*
类内实现的成员方法默认会被建议为内联（默认加上
对于大类更多时候在类外实现，为了人看代码的方便、清晰
*/
List::List()
{
	_head = new Node();
	_tail = _head;
}
List::List(const List& src)
{
	//申请新结点
	_head = new Node();
	_tail = _head;
	//遍历src链表，将每个数据push_back插入到新链表
	Node* tmp = src._head->_next;//next是私有的，只能加友元
	while (NULL != tmp)
	{
		push_back(tmp->_val);
		tmp = tmp->_next;
	}

}
List::~List()
{
	while (!is_empty())
	{
		pop_back();
	}
	//删除头结点
	delete _head;
}
List& List::operator=(const List& src)
{
	if (this == &src)
	{
		return *this;
	}
	//1.清空目标链表。2.防止内存泄露
	while (!is_empty())
	{
		pop_back();
	}

	//拷贝
	Node* tmp = src._head->_next;
	while (NULL != tmp)
	{
		push_back(tmp->_val);
		tmp = tmp->_next;
	}
	return *this;
}
void List::push_back(int val)
{
	Node* node = new Node(val);
	_tail->_next = node;
	node->_pre = _tail;
	_tail = node;
}
void List::pop_back()
{
	if (is_empty())
	{
		return;
	}
	_tail = _tail->_pre;
	delete _tail->_next;
	_tail->_next = NULL;
}
void List::push_front(int val)
{

	Node* newnode = new Node(val);//构造好时的节点的next和pre已经为NULL了
	newnode->_pre = _head;
	//空链表的情况，即_head->_next为NULL
	if (!is_empty())
	{
		newnode->_next = _head->_next;//没必要，构造好时的节点的next和pre已经为NULL了
		_head->_next->_pre = newnode;//NULL就异常了
	}
	else
	{
		_tail = newnode;
	}
	_head->_next = newnode;

}
void List::pop_front(int *pval)
{
	if (is_empty())
	{
		return;
	}
	Node* tmp = _head->_next;
	if (NULL != tmp->_next)
	{
		tmp->_next->_pre = _head;
	}
	else
	{
		//如果删除的是当前链表的唯一实际节点
		_tail = _head;
	}
	_head->_next = tmp->_next;
	*pval = tmp->_val;
	delete tmp;
}

bool List::get_back(int* pval)
{
	if (is_empty())
	{
		return false;
	}
	*pval = _tail->_val;
	return true;
}
bool List::get_front(int* pval)
{
	if (is_empty())
	{
		return false;
	}
	*pval = _head->_next->_val;
	return true;
}
bool List::is_empty()
{
	return _head->_next == NULL;
}
int List::size()
{
	int i = 0;
	Node* p = _head->_next;
	while (p != NULL)
	{
		i++;
		p = p->_next;
	}
	return i;
}
void show(List& list)
{

	List::Node* p = list._head->_next;
	while (p != NULL)
	{
		printf("%d ", p->_val);
		p = p->_next;
	}
	printf("\n");
}
