```c
//.c
#include"lqueue.h"
#include<assert.h>
#include<stdlib.h>
#include<stdio.h>
QNode* Buy_node()
{
	QNode* s = (QNode*)malloc(sizeof(QNode));
	return s;
}
void Init_lqueue(LinkQueue* plq)
{
	assert(plq != NULL);
	QNode* node = Buy_node();
	node->next = NULL;
	plq->front = node;
	plq->tail = node;
}
//入队，尾插
bool Push_lqueue(LinkQueue* plq, ElemType val)
{
	assert(plq != NULL);
	QNode* newnode = Buy_node();
	if (NULL == newnode)return false;
	newnode->next = NULL;
	plq->tail->next = newnode;

	plq->tail = newnode;

	newnode->data = val;
	return true;
}
bool Pop_lqueue(LinkQueue* plq, ElemType* pval)
{
	assert(plq != NULL);
	if (Is_Empty_lqueue(plq))
	{
		return false;
	}
	QNode* oldnode = plq->front->next;
	*pval = oldnode->data;
	//头删
	plq->front->next = oldnode->next;
	free(oldnode);
	oldnode = NULL;
	return true;
}
bool Front_lqueue(LinkQueue* plq, ElemType* pval)
{
	assert(plq != NULL);
	if (Is_Empty_lqueue(plq))
	{
		return false;
	}
	*pval = plq->front->next->data;
	return true;
}
bool Is_Empty_lqueue(LinkQueue* plq)
{
	assert(plq != NULL);
	return plq->front->next == NULL;
}
int Get_Length_lqueue(LinkQueue* plq)
{
	assert(plq != NULL);
	int count = 0;
	QNode* p = plq->front->next;
	while (p != NULL)
	{
		count++;
		p = p->next;
	}
	return count;
}
void Clear_lqueue(LinkQueue* plq)
{
	assert(plq != NULL);
	int val;
	while (!Is_Empty_lqueue(plq))
	{
		Pop_lqueue(plq, &val);
	}
}
void Destroy_lqueue(LinkQueue* plq)
{
	assert(plq != NULL);
	Clear_lqueue(plq);
	free(plq->front);
	plq->front = NULL;
	plq->tail = NULL;
}
void Show_lqueue(LinkQueue* plq)
{
	assert(plq != NULL);
	QNode* p = plq->front->next;
	while (p != NULL)
	{
		printf("%d ", p->data);
		p = p->next;
	}
	printf("\n");
}

