```c
//.h
//LinkStack.h
#ifndef LINKSTACK_H
#define LINKSTACK_H

#define TRUE 1
#define FALSE 0
#define OK 1
#define ERROR 0
#define OVERFLOW -2
#define NULLPTR -3

typedef int Status;

typedef int SElemType;
typedef struct StackNode
{
    SElemType data;
    struct StackNode* next;
}StackNode, * PStackNode;
typedef struct
{
    StackNode* top;
    int cursize;
}LinkStack;

Status InitStack(LinkStack* ps);
void DestroyStack(LinkStack* ps);
void ClearStack(LinkStack* ps);
int StackLength(const LinkStack* ps);
bool StackEmpty(const LinkStack* ps);
Status Push_Stack(LinkStack* ps, SElemType val);
Status GetTop_Stack(LinkStack* ps, SElemType* pval);
Status Pop_Stack(LinkStack* ps, SElemType* pval);
bool DelFront_Stack(LinkStack* ps);
void Show_Stack(LinkStack* ps);
#endif
```

```c
//LinkStack.cpp
#include<stdlib.h>
#include<assert.h>
#include<string.h>
#include<stdio.h>
#include"LinkStack.h"
StackNode* Buynode()
{
    StackNode* newnode = (StackNode*)malloc(sizeof(StackNode));
    if (NULL != newnode)
    {
        memset(newnode, 0, sizeof(StackNode));
    }
    return newnode;
}
Status InitStack(LinkStack* ps)
{
    assert(ps != NULL);
    ps->top = Buynode();//头结点
    if (NULL == ps->top)return OVERFLOW;

    ps->cursize = 0;
    return OK;
}
void DestroyStack(LinkStack* ps)
{
    assert(ps != NULL);
    ClearStack(ps);
    free(ps->top);
    ps->top = NULL;
}
void ClearStack(LinkStack* ps)
{
    assert(ps != NULL);
    while (ps->cursize != 0)
    {
        DelFront_Stack(ps);
    }
}
int StackLength(const LinkStack* ps)
{
    assert(ps != NULL);
    return ps->cursize;
}
bool StackEmpty(const LinkStack* ps)
{
    assert(ps != NULL);
    return ps->cursize == 0;
}
Status Push_Stack(LinkStack* ps, SElemType val)
{
    assert(ps != NULL);
    StackNode* newnode = Buynode();
    if (NULL == newnode)return OVERFLOW;

    newnode->next = ps->top->next;
    ps->top->next = newnode;

    newnode->data = val;

    ps->cursize += 1;
    return OK;
}
Status GetTop_Stack(LinkStack* ps, SElemType* pval)
{
    assert(ps != NULL);
    if (pval == NULL)return NULLPTR;
    if (ps->cursize <= 0)return false;
    *pval = ps->top->next->data;
    return OK;
}
Status Pop_Stack(LinkStack* ps, SElemType* pval)
{
    assert(ps != NULL);
    if (pval == NULL)return NULLPTR;
    if (ps->cursize <= 0)return ERROR;
    GetTop_Stack(ps, pval);
    DelFront_Stack(ps);
    return OK;
}
bool DelFront_Stack(LinkStack* ps)
{
    assert(ps != NULL);
    if (ps->cursize <= 0)return false;
    StackNode* p = ps->top->next;
    ps->top->next = p->next;
    free(p);
    ps->cursize -= 1;
    return true;
}
void Show_Stack(LinkStack* ps)
{
    StackNode* p = ps->top->next;
    while (p != NULL)
    {
        printf("%d ", p->data);
        p = p->next;
    }
    //printf("\n");
}
