```c
//初始化
void Init_queue(Queue *pq)
{
    assert(pq!=NULL);
    pq->base = (ElemType*)malloc(sizeof(ElemType)*MAXSIZE);
    assert(pq->base !=NULL);
    pq->front = pq->tail = 0;
}
//入队
bool Push(Queue *pq, ElemType val)
{
    assert(pq!=NULL);
    if(IsFull(pq))
    {
        return false;
    }
    pq->base[pa->tail] = val;
    pq->tail = (pq->tail + 1) % MAXSIZE;
    return true;
}
//出队
bool Pop(Queue *pq, ElemType *pval)
{
    if(IsEmpty(pq))
    {
        return false;
    }
    *pval = pq->base[pq->front];
    pq->front = (pq->front + 1) % MAXSIZE;
    return true;
}
//获取队头元素值
bool Head(Queue *pq, ElemType *pval)
{
    if(IsEmpty(pq))
    {
        return false;
    }
    *pval = pq->base[pq->front];
    return true;
}
//获取有效值个数
int GetLength(Queue *pq)
{
	return (pq->tail - pq-> front + MAXSIZE) % MAXSIZE;
}
//判空
bool IsEmpty(Queue *pq)
{
    return pq->front == pq->tail;
}
//判满
bool IsFull(Queue *pq)
{
    return (pq->tail+1)%MAXSIZE == pq->front;
}
//清空
void Clear(Queue *pq)
{
    pq->tail = pq->front = 0;
}
//销毁
void Destroy(Queue *pq)
{
    free(pq->base);
    pq->base = NULL;
}
//show
void Show(Queue *pq)
{
    int p = pq->front;
    while(p != pq->tail)
    {
        printf("%d ",pq->base[p]);
        p = (p+1) % MAXSIZE;
    }
    printf("\n");
}
