    int b = _b + src._b;
    return Compare(a,b);
}
Complex operator-(const Complex& src)const
{
    int a = _a - src._a;
    int b = _b - src._b;
    return Compare(a,b);
}
bool operator&&(const Complex& src)const
{
    return _a && src._a;
}
void operator <<(ostream& out)
{
