void ReverseList(LinkList head)
{
    assert(head != NULL);
    ListNode *back = NULL;
    ListNode *temp = NULL;
    ListNode *front = head->next;
    while(front != NULL)
    {
        temp = front;
        front = front->next;
        temp->next = back;
        back = temp;
    }
    head->next = back;
}
