    struct ListNode *p = node->next;
    *node=*p;
    free(p);
}
```

如果考虑最后节点，就没办法用这种方法了，因为最多只能给最后的节点的信息全赋零值，并且前继节点的next指向的地址是无法改变的。

# 刷题碰到的

## 解决哈希冲突-公共溢出区法

![image-20210921020227197](/images/%E5%AD%98%E7%96%91%E8%AE%B0%E5%BD%95/image-20210921020227197.png)

![image-20210921020240377](/images/%E5%AD%98%E7%96%91%E8%AE%B0%E5%BD%95/image-20210921020240377.png)

https://blog.csdn.net/ycwasdfasdf/article/details/52232502

![image-20210921020448550](/images/%E5%AD%98%E7%96%91%E8%AE%B0%E5%BD%95/image-20210921020448550.png)

```c++
//https://blog.csdn.net/HLW0522/article/details/52086598
#include<iostream>
using namespace std;
#define HASHSIZE 10
#define NULLKEY -32768
typedef struct hash
{
	int *element;
	int *extraElement;//溢出区表
	int count; // 溢出区的元素个数
}HashTable;
// 由于 通过哈希函数 计算后的地址重复几率很小，所以把重复部分用顺序表来存放，查找时遍历这个公共溢出区的顺序表，效率会更高。
void Init(HashTable *p)
{
	p->element = (int*)malloc(sizeof(int)*HASHSIZE);
	p->extraElement = (int*)malloc(sizeof(int)*HASHSIZE);
	for (int i = 0; i < HASHSIZE; ++i)
	{
		p->element[i] = NULLKEY;
		p->extraElement[i] = NULLKEY; 
	}
	p->count = 0; 
}
// 除留余数法
int HASH(int key)
{
	return key%HASHSIZE;
}
//插入元素
void InsertHash(HashTable *p, int key)
{
	int addr = HASH(key);
	//处理冲突, 使用公共溢出法
	if (p->element[addr] == NULLKEY)
		p->element[addr] = key;
	else //如果元素内已经有值了，就放到溢出部分的表中，且把count加 1
		p->extraElement[p->count++] = key;
}
int Search(HashTable *p, int key)
{
	int addr = HASH(key);
	if (key == p->element[addr])
		return addr;
	else
	{
		for (int i = 0; i < p->count; ++i)
			if (p->extraElement[i] == key)
			{
				cout << "溢出表" << endl;
				return i;
			}
	}
	return -1;
}
int main(void)
{
	int a[10] = { 12,45,2,6,78,9,0,1,15 };
	HashTable table;
	Init(&table);
	for (int i = 0; i < 10; i++)
		InsertHash(&table, a[i]);

	int res = Search(&table, 2);
	if (res != -1)
		cout << "查找成功！地址为： " << res << endl;
	else
		cout << "查找失败！ " << endl;
	system("pause");
	return 0;
}
```

# 线性表

线性表(linear_list)是最常用且最简单的一种数据结构。简言之，**一个线性表是n个数据元素的有限序列**。至于每个数据元素的具体含义，在不同的情况下各不相同，它可以是一个整数或一个字符，也可以是一页书，甚至其他更复杂的信息。

## 线性结构的特点

1. 存在惟一的一个被称作“第一个”的数据元素；
2. 存在惟一的一个被称作“最后一个”的数据元素；
3. 除第一个之外，集合中的每个数据元素均只有一个前驱；
4. 除最后一个之外，集合中每个数据元素均只有一个后继；

![image-20210914180221393](/images/%E5%9F%BA%E7%A1%80%E6%95%B0%E6%8D%AE%E7%BB%93%E6%9E%84_%E7%BA%BF%E6%80%A7%E8%A1%A8%E6%A6%82%E6%8B%AC&%E9%A1%BA%E5%BA%8F%E8%A1%A8/image-20210914180221393.png)

概括来讲，最大的特点就是“**元素之间一对一**”的特点，即特点3和4；另外的一个标志就是，**它是连续不间断的**。

最后还要说明的是，虽然我们对线性表的定义中没有要求n个数据元素是相同类型的，但是**我们在编程的实际应用中只研究数据元素具有相同类型的线性表**。因为无类型的泛型线性表没有研究价值和意义。

```c
int main()
{
    int ar[10] = {12,23,34,45,56,67};
    double dx[10] = {12.23, 23.34, 34.45};

    //以下泛型线性表我们不做研究
    {12, 45.56, 'a', {"09001","yhping","man"}, "hmin"};
}
```

数据元素类型相同的线性表的相邻数据元素之间存在序偶关系。若将含有n个元素的线性表记为：
$$
(a_0,a_1,...,a_{i-1},a_i,a_{i+1},...,a_{n-1})
$$
则表中$a_{i-1}$领先于$a_{i}$，$a_{i}$领先于$a_{i+1}$。称$a_{i-1}$是$a_{i}$的直接前驱元素，$a_{i+1}$是$a_{i}$的直接后继元素。当$i=0,2,...,n-2$时，$a_{i}$有且仅有一个直接后继，当$i=1,2,...,n-1$时，$a_{i}$有且仅有一个直接前驱。

## 总结

线性表的决定性特征：

1. 一对一
2. 连续不间断

# 顺序表

顺序表是线性表的一种表示和实现方式。指的是用一组地址连续的存储单元依次存储线性表的数据元素。

