#include<stdlib.h>
int main()
{
    char* pch = (char*)calloc(1,3);
    for(int i = 0;i<2;++i)
    {
        pch[i] = getchar();
    }
    getchar();//消除回车
	putchar(pch[0]);
	putchar(pch[1]);
    return 0;
}
```

比如getchar()，通过调试，我们发现：

```c
