```c
//MyLinkList.cpp
#include<stdio.h>
#include"MyLinkList.h"
void ListSave(LinkList* plist)
{
    assert(plist!=NULL);
    if(IsEmpty(plist))return;
    FILE* pf = NULL;
    errno_t tag = fopen_s(&pf,"List.dat","wb");
    if(fp == NULL)
    {
		printf("file open error:%d\n",tag);
        exit(1);
    }
    fprintf(pf,"%d\n",plist->cursize);
    ListNode* pnode = plist->head->next;
    while(pnode!=NULL)
    {
        fprintf(pf,"%d\n",pnode->data);
        pnode=pnode->next;
    }
    fclose(pf);
    pf=NULL;
}
void ListLoad(LinkList* plist)
{
    assert(plist!=NULL);
    FILE* pf = NULL;
    errno_t tag = fopen_s(&pf,"List.dat","rb");
    if(pf==NULL)
    {
        printf("file open error:%d\n");
        exit(1);
    }
    int n = 0;
    fscanf_s(pf,"%d",&n);
    for(int i = 0;i<n;++i)
    {
        int val=0;
        fscanf_s(pf,"%d",&val);
        Push_Back(plist,val);
    }
    fclose(pf);
    pf=NULL;
}
int main()
{
    LinkList mylist;
    InitLink(&mylist);

    int val;
    while(scanf_s("%d",&val),val!=-1)
    {
        Push_Front(&mylist,val);
    }
    PrintLink(&mylist);
    //以上程序运行时，输入12 23 34 45 56 67 78 89 90 100 -1
    //输入100 90 89 78 67 56 45 34 23 12 （因为是头插）
    ListSave(&mylist);

    LinkList newlist;
    InitLink(&newlist);
    ListLoad(&newlist);
    PrintLink(&newlist);


    DestoryLink(&mylist);
    DestoryLink(&newlist);
    return 0;
}
