<img src="/images/C%E8%AF%AD%E8%A8%80_%E9%80%92%E5%BD%92/image-20210816014510751.png" alt="image-20210816014510751" style="zoom:80%;" />

```c
void fun(int* ar,int* br,int i,int n)
{
    if(i==n)
    {
        for(int k=0;i<n;++k)
        {
            if(br[k]==1)
            {
                printf("%d ",ar[k]);
            }
        }
        printf("\n");

    }
    else
    {
        br[i]=1;
        fun(i+1,n);
        br[i]=0;
        fun(i+1,n);
    }
